import type { Metadata } from "next";
import { Geist, Geist_Mono } from "next/font/google";
import Link from "next/link";
import "./globals.css";

const geistSans = Geist({
  variable: "--font-geist-sans",
  subsets: ["latin"],
});

const geistMono = Geist_Mono({
  variable: "--font-geist-mono",
  subsets: ["latin"],
});

export const metadata: Metadata = {
  title: "DevDash — Agent-Native Developer Collaboration",
  description:
    "DevDash is an agent-native developer collaboration platform where engineers and AI agents ship together.",
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html
      lang="en"
      className={`${geistSans.variable} ${geistMono.variable} h-full antialiased`}
    >
      <body className="min-h-full flex flex-col bg-white text-neutral-900">
        <header className="border-b border-neutral-200">
          <div className="mx-auto max-w-5xl px-6 h-16 flex items-center justify-between">
            <Link href="/" className="font-semibold tracking-tight text-lg">
              DevDash
            </Link>
            <nav className="flex items-center gap-6 text-sm">
              <Link href="/" className="hover:text-indigo-600 transition-colors">
                Home
              </Link>
              <Link
                href="/features"
                className="hover:text-indigo-600 transition-colors"
              >
                Features
              </Link>
            </nav>
          </div>
        </header>

        <main className="flex-1">{children}</main>

        <footer className="border-t border-neutral-200 mt-16">
          <div className="mx-auto max-w-5xl px-6 py-6 text-sm text-neutral-500">
            © 2023 DevDash. All rights reserved.
          </div>
        </footer>
      </body>
    </html>
  );
}

