import Link from "next/link";

const features = [
  {
    title: "Shared agent workspace",
    body: "Humans and agents work in the same project, with shared files, threads, and task state. No more copy-paste bridges between tools.",
  },
  {
    title: "Reviewable agent work",
    body: "Every agent action — edits, commands, decisions — is captured as a reviewable trace you can replay, comment on, and learn from.",
  },
  {
    title: "Workflows, not one-shots",
    body: "Compose agents into durable workflows: prime context, draft changes, open a PR, respond to review. Repeatable across your team.",
  },
  {
    title: "Plugs into your stack",
    body: "GitHub, Linear, Slack, your CI — DevDash meets your team where it already works instead of asking you to migrate.",
  },
];

export default function FeaturesPage() {
  return (
    <div className="mx-auto max-w-5xl px-6 py-20">
      <div className="mb-12">
        <h1 className="text-4xl font-semibold tracking-tight mb-4">Features</h1>
        <p className="max-w-2xl text-neutral-600">
          A quick look at what makes DevDash different from bolt-on AI
          assistants.
        </p>
      </div>

      <div className="grid gap-6 sm:grid-cols-2">
        {features.map((f, i) => (
          <div
            key={f.title}
            className={
              i === 2
                ? "rounded-lg border border-yellow-400 bg-yellow-50 p-6"
                : "rounded-lg border border-neutral-200 bg-white p-6"
            }
          >
            <h2 className="text-lg font-semibold mb-2">{f.title}</h2>
            <p className="text-sm text-neutral-600 leading-relaxed">{f.body}</p>
          </div>
        ))}
      </div>

      <div className="mt-16">
        <Link
          href="/"
          className="text-sm text-indigo-600 hover:text-indigo-700 transition-colors"
        >
          ← Back to home
        </Link>
      </div>
    </div>
  );
}

